mapper.select:
SELECT PRODUCT_ID AS productId, PLATFORM AS platform, PLATFORM_PRODUCT_ID AS platformProductId, PRODUCT_KEY AS productKey, PRODUCT_NAME AS productName, BRAND AS brand, CATEGORY AS category, PRICE AS price, AVG_RATING AS avgRating, TOTAL_REVIEW_COUNT AS totalReviewCount, OVERALL_POS_RATE AS overallPosRate, OVERALL_NEU_RATE AS overallNeuRate, OVERALL_NEG_RATE AS overallNegRate, BASE_SKIN_TYPE AS baseSkinType, SKIN_REVIEW_COUNT AS skinReviewCount, SKIN_POS_RATE AS skinPosRate, SKIN_NEU_RATE AS skinNeuRate, SKIN_NEG_RATE AS skinNegRate, TOP_NEED_TAGS AS topNeedTags, TOP_CONCERN_TAGS AS topConcernTags, CAUTION_LEVEL AS cautionLevel, RECOMMENDATION_SCORE AS recommendationScore, RECOMMENDATION_TIER AS recommendationTier, EVIDENCE_LEVEL AS evidenceLevel, TO_CHAR(REG_DATE, 'YYYY-MM-DD') AS regDate, PRODUCT_URL AS productUrl, IMAGE_URL AS imageUrl, IMAGE_STATUS AS imageStatus, (SELECT COUNT(*) FROM BL_PRODUCT_FAVORITES fav WHERE fav.PRODUCT_ID = BL_PRODUCTS.PRODUCT_ID) AS favoriteCount, (SELECT COUNT(*) FROM BL_PRODUCT_RATINGS rt WHERE rt.PRODUCT_ID = BL_PRODUCTS.PRODUCT_ID) AS siteRatingCount, (SELECT ROUND(AVG(rt.RATING), 2) FROM BL_PRODUCT_RATINGS rt WHERE rt.PRODUCT_ID = BL_PRODUCTS.PRODUCT_ID) AS siteRatingAvg, (SELECT COUNT(*) FROM BL_USER_PRODUCT_EVENTS ev WHERE ev.PRODUCT_ID = BL_PRODUCTS.PRODUCT_ID AND ev.EVENT_TYPE IN ('VIEW', 'DETAIL_VIEW')) AS viewCount, (SELECT COUNT(*) FROM BL_PRODUCT_COMMENTS c WHERE c.PRODUCT_ID = BL_PRODUCTS.PRODUCT_ID AND c.STATUS = 'ACTIVE') AS commentCount FROM BL_PRODUCTS
AND NOT EXISTS ( SELECT 1 FROM BL_PRODUCT_ADMIN_FLAGS af WHERE af.PRODUCT_ID = BL_PRODUCTS.PRODUCT_ID AND af.IS_VISIBLE = 'N' )
AND (PRODUCT_NAME LIKE '%' || #{keyword} || '%' OR BRAND LIKE '%' || #{keyword} || '%')
AND CATEGORY = #{category}
AND BRAND = #{brand}
AND BASE_SKIN_TYPE = #{skinType}
AND PLATFORM = #{platform}
AND IMAGE_URL IS NOT NULL AND IMAGE_STATUS = 'found'
ORDER BY RECOMMENDATION_SCORE DESC NULLS LAST ORDER BY AVG_RATING DESC NULLS LAST ORDER BY TOTAL_REVIEW_COUNT DESC NULLS LAST ORDER BY PRODUCT_ID DESC
OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY
